{
  "name": "Finance Manager",
  "level": "unit",
  "description": "Access to payroll and financial reports",
  "permissions": [
    "{{role_id}}"
  ]
}

{
  "name": "Standard Payroll Policy",
  "taxCompliance": {
    "providentFund": {
      "enabled": true,
      "employeeRate": 12,
      "employerRate": 12,
      "ceiling": 15000
    },
    "esi": {
      "enabled": true,
      "employeeRate": 0.75
    },
    "tds": {
      "enabled": false,
      "annualTax": 0
    }
  },
  "lopDeduction": {
    "enabled": true
  },
  "overtimePay": {
    "enabled": true,
    "ratePerHour": 300
  },
  "applicableFor": {
    "employmentTypes": [
      "FULL_TIME"
    ]
  }
}
